  1→import SwiftUI
  2→
  3→/// Today's session list — the hero view of Pablo Companion.
  4→///
  5→/// Shows scheduled sessions, provides Start Session + Quick Start flows,
  6→/// and polls the backend every 30 seconds to keep statuses fresh.
  7→struct DayView: View {
  8→    var sessionVM: SessionViewModel
  9→    var patients: [Patient]
 10→    var isLoadingPatients: Bool
 11→    @Binding var patientSearchText: String
 12→    var recordingState: RecordingUIState = .idle
 13→    var recordingDuration: TimeInterval = 0
 14→    var onStartSession: ((Session) -> Void)?
 15→    var onQuickStart: ((Patient) -> Void)?
 16→    var onStopRecording: (() -> Void)?
 17→
 18→    @State private var lastRefreshDate = Date()
 19→    @State private var showingQuickStart = false
 20→
 21→    var body: some View {
 22→        VStack(spacing: 0) {
 23→            header
 24→            if recordingState != .idle {
 25→                recordingBanner
 26→            }
 27→            Divider()
 28→            content
 29→        }
 30→        .background(Color.pabloCream)
 31→        .task { await pollSessions() }
 32→        .sheet(isPresented: $showingQuickStart) {
 33→            QuickStartSheet(
 34→                patients: patients,
 35→                isLoading: isLoadingPatients,
 36→                searchText: $patientSearchText,
 37→                onSelect: { patient in onQuickStart?(patient) }
 38→            )
 39→        }
 40→    }
 41→
 42→    // MARK: - Header
 43→
 44→    private var header: some View {
 45→        HStack {
 46→            VStack(alignment: .leading, spacing: 4) {
 47→                Text(greeting)
 48→                    .font(.pabloDisplay(24))
 49→                    .foregroundStyle(Color.pabloBrownDeep)
 50→                Text(formattedDate)
 51→                    .font(.pabloBody(14))
 52→                    .foregroundStyle(Color.pabloBrownSoft)
 53→            }
 54→            Spacer()
 55→            if sessionVM.isLoading {
 56→                ProgressView().controlSize(.small)
 57→            }
 58→            sessionCountBadge
 59→            quickStartButton
 60→        }
 61→        .padding(.horizontal, 20)
 62→        .padding(.vertical, 16)
 63→    }
 64→
 65→    private var sessionCountBadge: some View {
 66→        Group {
 67→            if !sessionVM.todaySessions.isEmpty {
 68→                Text("\(sessionVM.todaySessions.count)")
 69→                    .font(.pabloBody(12))
 70→                    .foregroundStyle(Color.pabloBrownDeep)
 71→                    .frame(width: 24, height: 24)
 72→                    .background(Color.pabloHoney.opacity(0.2))
 73→                    .clipShape(Circle())
 74→            }
 75→        }
 76→    }
 77→
 78→    private var quickStartButton: some View {
 79→        Button { showingQuickStart = true } label: {
 80→            Label("Quick Start", systemImage: "plus.circle.fill")
 81→                .font(.pabloBody(13))
 82→                .foregroundStyle(Color.pabloBrownDeep)
 83→                .padding(.horizontal, 10)
 84→                .padding(.vertical, 6)
 85→                .background(Color.pabloHoney)
 86→                .clipShape(RoundedRectangle(cornerRadius: 8))
 87→        }
 88→        .buttonStyle(.plain)
 89→    }
 90→
 91→    // MARK: - Recording Banner
 92→
 93→    private var recordingBanner: some View {
 94→        HStack(spacing: 12) {
 95→            Circle()
 96→                .fill(Color.pabloSage)
 97→                .frame(width: 10, height: 10)
 98→                .overlay(
 99→                    Circle()
100→                        .fill(Color.pabloSage.opacity(0.4))
101→                        .frame(width: 18, height: 18)
102→                )
103→
104→            Text(recordingState == .paused ? "Paused" : "Recording")
105→                .font(.pabloBody(14))
106→                .fontWeight(.medium)
107→                .foregroundStyle(Color.pabloBrownDeep)
108→
109→            Text(formattedDuration(recordingDuration))
110→                .font(.system(size: 14, design: .monospaced))
111→                .foregroundStyle(Color.pabloBrownSoft)
112→
113→            Spacer()
114→
115→            Button {
116→                onStopRecording?()
117→            } label: {
118→                Label("Stop", systemImage: "stop.fill")
119→                    .font(.pabloBody(13))
120→                    .foregroundStyle(.white)
121→                    .padding(.horizontal, 12)
122→                    .padding(.vertical, 6)
123→                    .background(Color.pabloError)
124→                    .clipShape(RoundedRectangle(cornerRadius: 8))
125→            }
126→            .buttonStyle(.plain)
127→        }
128→        .padding(.horizontal, 20)
129→        .padding(.vertical, 10)
130→        .background(Color.pabloSage.opacity(0.1))
131→    }
132→
133→    private func formattedDuration(_ duration: TimeInterval) -> String {
134→        let minutes = Int(duration) / 60
135→        let seconds = Int(duration) % 60
136→        return String(format: "%d:%02d", minutes, seconds)
137→    }
138→
139→    // MARK: - Content
140→
141→    @ViewBuilder
142→    private var content: some View {
143→        if sessionVM.isLoading, sessionVM.todaySessions.isEmpty {
144→            loadingState
145→        } else if sessionVM.todaySessions.isEmpty {
146→            emptyState
147→        } else {
148→            sessionList
149→        }
150→    }
