  1→// session_pipeline.rs — 1:1 session transcription pipeline.
  2→//
  3→// Pipeline (1:1 mode, no diarization needed):
  4→//   mic file   → preprocess → Whisper → all segments labeled THERAPIST
  5→//   system file → preprocess → Whisper → all segments labeled CLIENT
  6→//   merge both lists sorted by start time → TranscriptResult
  7→//
  8→// System audio file is optional: some recordings may have mic only (e.g. phone
  9→// sessions where system audio capture was unavailable).
 10→
 11→use crate::{
 12→    audio_preprocessing, whisper_transcriber, PabloError, SessionMode, SpeakerLabel,
 13→    TranscriptResult, TranscriptSegment, TranscriptionConfig,
 14→};
 15→
 16→pub async fn transcribe_session_1on1(
 17→    session_id: String,
 18→    mic_path: String,
 19→    system_path: Option<String>,
 20→    config: TranscriptionConfig,
 21→) -> Result<TranscriptResult, PabloError> {
 22→    // ── Mic pass: all segments → THERAPIST ───────────────────────────────────
 23→    let mic_audio =
 24→        audio_preprocessing::preprocess_pcm(mic_path, config.mic_channels, config.mic_sample_rate)
 25→            .await?;
 26→
 27→    let mic_raw =
 28→        whisper_transcriber::transcribe_audio(config.model_path.clone(), mic_audio).await?;
 29→
 30→    let mut segments: Vec<TranscriptSegment> = mic_raw
 31→        .into_iter()
 32→        .map(|s| TranscriptSegment {
 33→            speaker: SpeakerLabel::Therapist,
 34→            start_seconds: s.start_ms as f64 / 1000.0,
 35→            end_seconds: s.end_ms as f64 / 1000.0,
 36→            text: s.text,
 37→        })
 38→        .collect();
 39→
 40→    // ── System audio pass: all segments → CLIENT ─────────────────────────────
 41→    if let Some(sys_path) = system_path {
 42→        let sys_audio = audio_preprocessing::preprocess_pcm(
 43→            sys_path,
 44→            config.system_channels,
 45→            config.system_sample_rate,
 46→        )
 47→        .await?;
 48→
 49→        let sys_raw = whisper_transcriber::transcribe_audio(config.model_path, sys_audio).await?;
 50→
 51→        for s in sys_raw {
 52→            segments.push(TranscriptSegment {
 53→                speaker: SpeakerLabel::Client,
 54→                start_seconds: s.start_ms as f64 / 1000.0,
 55→                end_seconds: s.end_ms as f64 / 1000.0,
 56→                text: s.text,
 57→            });
 58→        }
 59→    }
 60→
 61→    // ── Merge: sort by start time ─────────────────────────────────────────────
 62→    segments.sort_by(|a, b| {
 63→        a.start_seconds
 64→            .partial_cmp(&b.start_seconds)
 65→            .unwrap_or(std::cmp::Ordering::Equal)
 66→    });
 67→
 68→    Ok(TranscriptResult {
 69→        session_id,
 70→        session_mode: SessionMode::OneToOne,
 71→        segments,
 72→    })
 73→}
 74→
 75→// ── Tests ─────────────────────────────────────────────────────────────────────
 76→
 77→#[cfg(test)]
 78→mod tests {
 79→    use super::*;
 80→    use crate::TranscriptionConfig;
 81→
 82→    fn make_config() -> TranscriptionConfig {
 83→        TranscriptionConfig {
 84→            model_path: "nonexistent.bin".to_string(),
 85→            mic_channels: 1,
 86→            mic_sample_rate: 48000,
 87→            system_channels: 2,
 88→            system_sample_rate: 48000,
 89→        }
 90→    }
 91→
 92→    #[test]
 93→    fn merge_sorts_by_start_time() {
 94→        // Build two interleaved segment lists and verify sort order
 95→        let mut segments = vec![
 96→            TranscriptSegment {
 97→                speaker: SpeakerLabel::Therapist,
 98→                start_seconds: 5.0,
 99→                end_seconds: 7.0,
100→                text: "b".to_string(),
101→            },
102→            TranscriptSegment {
103→                speaker: SpeakerLabel::Client,
104→                start_seconds: 2.0,
105→                end_seconds: 4.0,
106→                text: "a".to_string(),
107→            },
108→            TranscriptSegment {
109→                speaker: SpeakerLabel::Therapist,
110→                start_seconds: 9.0,
111→                end_seconds: 11.0,
112→                text: "c".to_string(),
113→            },
114→        ];
115→        segments.sort_by(|a, b| {
116→            a.start_seconds
117→                .partial_cmp(&b.start_seconds)
118→                .unwrap_or(std::cmp::Ordering::Equal)
119→        });
120→        assert_eq!(segments[0].start_seconds, 2.0);
121→        assert_eq!(segments[1].start_seconds, 5.0);
122→        assert_eq!(segments[2].start_seconds, 9.0);
123→    }
124→
125→    #[test]
126→    fn config_fields_accessible() {
127→        let c = make_config();
128→        assert_eq!(c.mic_channels, 1);
129→        assert_eq!(c.system_channels, 2);
130→        assert_eq!(c.mic_sample_rate, 48000);
131→        assert_eq!(c.system_sample_rate, 48000);
132→    }
133→
134→    #[tokio::test]
135→    async fn mic_only_silent_audio_returns_empty_transcript() {
136→        use std::io::Write;
137→        let dir = std::env::temp_dir();
138→        let mic_path = dir.join("test_mic.pcm");
139→
140→        // Write a tiny valid mono 48kHz PCM file (100 silent samples)
141→        let mut f = std::fs::File::create(&mic_path).unwrap();
142→        let samples: Vec<i16> = vec![0i16; 100];
143→        for s in &samples {
144→            f.write_all(&s.to_le_bytes()).unwrap();
145→        }
146→
147→        let config = make_config();
148→        // Silent audio → VAD finds no speech → empty transcript (no model load needed)
149→        let result = transcribe_session_1on1(
150→            "test-session".to_string(),
151→            mic_path.to_str().unwrap().to_string(),
152→            None,
153→            config,
154→        )
155→        .await;
156→
157→        std::fs::remove_file(&mic_path).ok();
158→        let transcript = result.unwrap();
159→        assert!(transcript.segments.is_empty());
160→    }
161→}
