  1→// whisper_transcriber.rs — Whisper-based ASR via whisper-rs.
  2→//
  3→// Pipeline: audio → VAD split → transcribe each speech chunk → reassemble.
  4→//
  5→// The audio is scanned for speech regions using RMS energy detection. Each
  6→// contiguous speech region is fed to Whisper independently, so the model never
  7→// sees long silence gaps and can't bridge across them. Segment timestamps are
  8→// offset back to the original file timeline.
  9→//
 10→// Fixed inference params (per design doc §4):
 11→//   language      = en
 12→//   token_timestamps = true   (required for diarization alignment downstream)
 13→//   beam_size     = 5
 14→
 15→use crate::PabloError;
 16→use whisper_rs::{FullParams, SamplingStrategy, WhisperContext, WhisperContextParameters};
 17→
 18→/// Sample rate of audio fed to Whisper (always 16 kHz after preprocessing).
 19→const WHISPER_SAMPLE_RATE: usize = 16000;
 20→
 21→/// RMS energy below this threshold = silence.
 22→const SILENCE_RMS_THRESHOLD: f32 = 0.01;
 23→
 24→/// Window size in samples for VAD scanning (20ms at 16 kHz = 320 samples).
 25→const VAD_WINDOW_SAMPLES: usize = (WHISPER_SAMPLE_RATE * 20) / 1000;
 26→
 27→/// Minimum silence gap in ms to split speech regions. Gaps shorter than this
 28→/// are treated as part of the same utterance (natural pauses within a sentence).
 29→const MIN_SILENCE_GAP_MS: usize = 500;
 30→
 31→// ── Public types ──────────────────────────────────────────────────────────────
 32→
 33→/// A single raw ASR segment as returned by Whisper.
 34→/// Timestamps are in milliseconds.
 35→#[derive(Debug, Clone)]
 36→pub struct RawSegment {
 37→    pub start_ms: i64,
 38→    pub end_ms: i64,
 39→    pub text: String,
 40→}
 41→
 42→/// A contiguous region of speech detected by VAD.
 43→#[derive(Debug, Clone)]
 44→struct SpeechRegion {
 45→    start_sample: usize,
 46→    end_sample: usize,
 47→}
 48→
 49→impl SpeechRegion {
 50→    fn start_ms(&self) -> i64 {
 51→        (self.start_sample * 1000 / WHISPER_SAMPLE_RATE) as i64
 52→    }
 53→
 54→    fn samples<'a>(&self, audio: &'a [f32]) -> &'a [f32] {
 55→        &audio[self.start_sample..self.end_sample.min(audio.len())]
 56→    }
 57→}
 58→
 59→// ── Public API ────────────────────────────────────────────────────────────────
 60→
 61→/// Load the GGML model at `model_path` and transcribe `audio` (16 kHz mono f32).
 62→///
 63→/// The audio is split at silence boundaries before transcription so that
 64→/// Whisper processes each speech region independently. This prevents the model
 65→/// from bridging across silence gaps (which causes timestamp errors and
 66→/// hallucinations).
 67→///
 68→/// Returns one `RawSegment` per Whisper sentence segment, ordered by start time.
 69→/// Empty or silent audio returns an empty Vec.
 70→pub async fn transcribe_audio(
 71→    model_path: String,
 72→    audio: Vec<f32>,
 73→) -> Result<Vec<RawSegment>, PabloError> {
 74→    tokio::task::spawn_blocking(move || run_transcription(&model_path, &audio))
 75→        .await
 76→        .map_err(|e| PabloError::WhisperTranscribe {
 77→            message: format!("transcription thread panicked: {e}"),
 78→        })?
 79→}
 80→
 81→// ── Private helpers ───────────────────────────────────────────────────────────
 82→
 83→fn run_transcription(model_path: &str, audio: &[f32]) -> Result<Vec<RawSegment>, PabloError> {
 84→    // 1. Find speech regions via VAD
 85→    let regions = detect_speech_regions(audio);
 86→    if regions.is_empty() {
 87→        return Ok(Vec::new());
 88→    }
 89→
 90→    // 2. Load model once, reuse for all chunks
 91→    let ctx = WhisperContext::new_with_params(model_path, WhisperContextParameters::default())
 92→        .map_err(|e| PabloError::WhisperInit {
 93→            message: format!("failed to load model '{model_path}': {e}"),
 94→        })?;
 95→
 96→    // 3. Transcribe each speech region independently
 97→    let mut all_segments = Vec::new();
 98→    for region in &regions {
 99→        let chunk = region.samples(audio);
100→        let offset_ms = region.start_ms();
101→
102→        let chunk_segments = transcribe_chunk(&ctx, chunk, offset_ms)?;
103→        all_segments.extend(chunk_segments);
104→    }
105→
106→    Ok(all_segments)
107→}
108→
109→/// Transcribe a single speech chunk using an already-loaded model context.
110→/// Whisper timestamps are relative to the chunk start; `offset_ms` shifts
111→/// them back to the original file timeline.
112→fn transcribe_chunk(
113→    ctx: &WhisperContext,
114→    audio: &[f32],
115→    offset_ms: i64,
116→) -> Result<Vec<RawSegment>, PabloError> {
117→    let mut state = ctx.create_state().map_err(|e| PabloError::WhisperInit {
118→        message: format!("failed to create whisper state: {e}"),
119→    })?;
120→
121→    let mut params = FullParams::new(SamplingStrategy::BeamSearch {
122→        beam_size: 5,
123→        patience: -1.0,
124→    });
125→    params.set_language(Some("en"));
126→    params.set_token_timestamps(true);
127→
128→    state
129→        .full(params, audio)
130→        .map_err(|e| PabloError::WhisperTranscribe {
131→            message: format!("whisper inference failed: {e}"),
132→        })?;
133→
134→    let mut segments = Vec::new();
135→    for seg in state.as_iter() {
136→        let start_ms = seg.start_timestamp() * 10 + offset_ms;
137→        let end_ms = seg.end_timestamp() * 10 + offset_ms;
138→
139→        let text = clean_text(
140→            &seg.to_str_lossy()
141→                .map_err(|e| PabloError::WhisperTranscribe {
142→                    message: format!("invalid UTF-8 in segment: {e}"),
143→                })?,
144→        );
145→
146→        if text.is_empty() {
147→            continue;
148→        }
149→
150→        segments.push(RawSegment {
151→            start_ms,
152→            end_ms,
153→            text,
154→        });
155→    }
156→
157→    Ok(segments)
158→}
159→
160→/// Scan audio in small windows and return contiguous speech regions.
161→///
162→/// A speech region starts when RMS rises above the threshold and ends after
163→/// `MIN_SILENCE_GAP_MS` of consecutive silence. Short silence gaps within
164→/// speech (natural pauses) are absorbed into the region.
165→fn detect_speech_regions(audio: &[f32]) -> Vec<SpeechRegion> {
166→    let min_silence_windows =
167→        (MIN_SILENCE_GAP_MS * WHISPER_SAMPLE_RATE) / (1000 * VAD_WINDOW_SAMPLES);
168→    let mut regions = Vec::new();
169→    let mut in_speech = false;
170→    let mut region_start = 0;
171→    let mut silence_count = 0;
172→
173→    let mut pos = 0;
174→    while pos + VAD_WINDOW_SAMPLES <= audio.len() {
175→        let window = &audio[pos..pos + VAD_WINDOW_SAMPLES];
176→        let sum_sq: f64 = window.iter().map(|&s| (s as f64) * (s as f64)).sum();
177→        let rms = (sum_sq / window.len() as f64).sqrt() as f32;
178→        let is_speech = rms >= SILENCE_RMS_THRESHOLD;
179→
180→        if is_speech {
181→            if !in_speech {
182→                region_start = pos;
183→                in_speech = true;
184→            }
185→            silence_count = 0;
186→        } else if in_speech {
187→            silence_count += 1;
188→            if silence_count >= min_silence_windows {
189→                // End of speech region — rewind past the trailing silence
190→                let region_end = pos - (silence_count - 1) * VAD_WINDOW_SAMPLES;
191→                regions.push(SpeechRegion {
192→                    start_sample: region_start,
193→                    end_sample: region_end,
194→                });
195→                in_speech = false;
196→                silence_count = 0;
197→            }
198→        }
199→
200→        pos += VAD_WINDOW_SAMPLES;
201→    }
202→
203→    // Close any open region at end of audio
204→    if in_speech {
205→        regions.push(SpeechRegion {
206→            start_sample: region_start,
207→            end_sample: audio.len(),
208→        });
209→    }
210→
211→    regions
212→}
213→
214→/// Strip artifacts that Whisper sometimes adds to the text:
215→/// - Leading/trailing quotation marks (common with clear/scripted speech)
216→/// - Leading/trailing whitespace
217→fn clean_text(raw: &str) -> String {
218→    let trimmed = raw.trim();
219→    let stripped = trimmed
220→        .strip_prefix('"')
221→        .unwrap_or(trimmed)
222→        .strip_suffix('"')
223→        .unwrap_or(trimmed)
224→        .trim();
225→    stripped.to_string()
226→}
