// This file defines the Swift/Windows FFI boundary.
// Keep it thin and boring: simple value types, no generics, no closures.

namespace pablo_core {
    string core_version();

    [Async, Throws=PabloError]
    sequence<float> preprocess_pcm(string path, u8 channels, u32 sample_rate);

    [Async, Throws=PabloError]
    sequence<RawSegment> transcribe_audio(string model_path, sequence<float> audio);

    string render_google_meet(TranscriptResult transcript, GoogleMeetOptions opts);

    [Async, Throws=PabloError]
    TranscriptResult transcribe_session_1on1(
        string session_id,
        string mic_path,
        string? system_path,
        TranscriptionConfig config
    );

    // ── Pablo API endpoint functions ────────────────────────────────────────

    // Group A: ported from Swift (108.3)

    [Async, Throws=PabloError]
