    boolean baa_accepted;
    string? accepted_at;
};

// A patient record.
dictionary Patient {
    string id;
    string user_id;
    string first_name;
    string last_name;
    string? email;
    string? phone;
    string status;
    string? date_of_birth;
    string? diagnosis;
    u32 session_count;
    string? last_session_date;
    string? next_session_date;
    string created_at;
    string updated_at;
};

// Request body for creating a new patient.
dictionary CreatePatientRequest {
    string first_name;
    string last_name;
    string? email;
    string? phone;
    string? date_of_birth;
    string? diagnosis;
};

