                Image(systemName: "person.2.fill")
                    .foregroundStyle(Color.pabloSky)
            case .meet:
                Image(systemName: "globe")
                    .foregroundStyle(Color.pabloSky)
            case .none:
                EmptyView()
            }
        }
        .font(.pabloBody(12))
    }

    // MARK: - Formatting

    private var patientName: String {
        if let patient = session.patient {
