extension PabloError: Sendable {}
#endif

#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public struct FfiConverterTypePabloError: FfiConverterRustBuffer {
    typealias SwiftType = PabloError

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> PabloError {
        let variant: Int32 = try readInt(&buf)
        switch variant {




        case 1: return .AudioPreprocessing(
            message: try FfiConverterString.read(from: &buf)
            )
        case 2: return .WhisperInit(
            message: try FfiConverterString.read(from: &buf)
            )
        case 3: return .WhisperTranscribe(
            message: try FfiConverterString.read(from: &buf)
            )
        case 4: return .ApiClient(
            statusCode: try FfiConverterUInt16.read(from: &buf), 
            message: try FfiConverterString.read(from: &buf)
            )
        case 5: return .JsonParse(
            message: try FfiConverterString.read(from: &buf)
            )
        case 6: return .Unauthenticated
        case 7: return .Forbidden
        case 8: return .NotFound(
            resource: try FfiConverterString.read(from: &buf)
            )
        case 9: return .ConflictState(
            message: try FfiConverterString.read(from: &buf)
            )

         default: throw UniffiInternalError.unexpectedEnumCase
        }
    }

    public static func write(_ value: PabloError, into buf: inout [UInt8]) {
        switch value {





        case let .AudioPreprocessing(message):
            writeInt(&buf, Int32(1))
            FfiConverterString.write(message, into: &buf)


        case let .WhisperInit(message):
            writeInt(&buf, Int32(2))
            FfiConverterString.write(message, into: &buf)


        case let .WhisperTranscribe(message):
            writeInt(&buf, Int32(3))
            FfiConverterString.write(message, into: &buf)


        case let .ApiClient(statusCode,message):
            writeInt(&buf, Int32(4))
            FfiConverterUInt16.write(statusCode, into: &buf)
            FfiConverterString.write(message, into: &buf)


        case let .JsonParse(message):
            writeInt(&buf, Int32(5))
            FfiConverterString.write(message, into: &buf)


        case .Unauthenticated:
            writeInt(&buf, Int32(6))


        case .Forbidden:
            writeInt(&buf, Int32(7))


        case let .NotFound(resource):
            writeInt(&buf, Int32(8))
            FfiConverterString.write(resource, into: &buf)


        case let .ConflictState(message):
            writeInt(&buf, Int32(9))
            FfiConverterString.write(message, into: &buf)

        }
    }
}


